// Filter dan validasi output AI
const output = $input.first().json.output || '';

// Deteksi role dari response
const roleMatch = output.match(/\[ROLE:([\w_]+)\]/);
const detectedRole = roleMatch ? roleMatch[1] : 'umum';
const cleanOutput = output.replace(/\[ROLE:[\w_]+\]/g, '').trim();

return [{
  json: {
    reply: cleanOutput,
    detectedRole: detectedRole,
    timestamp: new Date().toISOString(),
    success: true
  }
}];
